// Generates 6 dark-gym-colored test clips using FFmpeg's built-in color source.
// Skips any clip that already exists (e.g. real clips from Stage 2).
// These are solid-color 1080x1920 clips so normalization in Assemble Video is a no-op.
const { execSync } = require('child_process');
const fs = require('fs');

const data   = $input.first().json;
const jobId  = data.job_id;
const n8nIn  = '/data/ffmpeg/input';
const contIn = '/ffmpeg/input';

if (!fs.existsSync(n8nIn)) fs.mkdirSync(n8nIn, { recursive: true });

// Dark cinematic gym colors per scene
const colors = ['0x1a1a2e', '0x0f2a4a', '0x0a1628', '0x1c0a3a', '0x0a2a20', '0x1a1a2e'];
const labels = ['HOOK', 'SETUP', 'EXECUTION', 'ANATOMY', 'KEY TIP', 'CTA'];

const clipPaths = data.clip_paths || [];

for (let i = 0; i < 6; i++) {
  const n8nPath  = n8nIn  + '/' + jobId + '_scene' + (i+1) + '.mp4';
  const contPath = contIn + '/' + jobId + '_scene' + (i+1) + '.mp4';

  // Use existing file if already downloaded from Stage 2
  if (fs.existsSync(n8nPath)) {
    console.log('Scene ' + (i+1) + ' already exists — using real Seedance clip.');
    if (!clipPaths[i]) clipPaths[i] = n8nPath;
    continue;
  }

  console.log('Generating test clip ' + (i+1) + '/6 (' + labels[i] + ')...');
  const cmd =
    'docker exec qpc_ffmpeg_runner ffmpeg -y ' +
    '-f lavfi -i "color=c=' + colors[i] + ':s=1080x1920:r=24:d=5" ' +
    '-f lavfi -i "sine=frequency=0:sample_rate=44100:duration=5" ' +
    '-c:v libx264 -crf 20 -preset fast -pix_fmt yuv420p ' +
    '-c:a aac -b:a 64k -shortest ' +
    '"' + contPath + '" && echo CLIP_OK';

  const res = execSync(cmd, { encoding: 'utf-8', timeout: 30000 });
  if (!res.includes('CLIP_OK')) throw new Error('Test clip ' + (i+1) + ' generation failed: ' + res.slice(-200));

  clipPaths[i] = n8nPath;
  console.log('  -> ' + n8nPath);
}

console.log('Test clips ready: ' + clipPaths.length + ' clips');
return [{ json: { ...data, clip_paths: clipPaths } }];

const raw  = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;
if (!body.job_id)     throw new Error('Stage 3 missing: job_id');
if (!body.clip_paths) throw new Error('Stage 3 missing: clip_paths');
