const { execSync } = require('child_process');
const fs = require('fs');

const data   = $input.first().json;
const jobId  = data.job_id;
const clips  = data.clip_paths || [];
const N      = clips.length;
const popup  = data.popup || {};
const muscleLabels = data.muscle_labels_scene4 || [];

const n8nIn  = '/data/ffmpeg/input';
const n8nOut = '/data/ffmpeg/output';
const contIn = '/ffmpeg/input';
const contOut= '/ffmpeg/output';

if (!fs.existsSync(n8nOut)) fs.mkdirSync(n8nOut, { recursive: true });

function run(cmd, ms) {
  ms = ms || 120000;
  console.log('CMD: ' + cmd.slice(0, 220));
  let out = '';
  try { out = execSync(cmd, { encoding: 'utf-8', timeout: ms }); }
  catch(e) { out = (e.stdout||'') + (e.stderr||''); }
  return out.toString();
}

// ─── STEP 1: Create iOS-style notification PNG (WhatsApp Messages style) ────
const overlayDir  = '/ffmpeg/config/overlay';
const notifBase   = overlayDir + '/ios_notification_bg.png';
const notifExists = run('docker exec qpc_ffmpeg_runner test -f "' + notifBase + '" && echo OK').includes('OK');

if (!notifExists) {
  run('docker exec qpc_ffmpeg_runner mkdir -p "' + overlayDir + '"');

  // Install Pillow if missing
  run('docker exec qpc_ffmpeg_runner pip install pillow --quiet 2>&1', 30000);

  // Write the notification card Python script
  const pyPath = n8nIn + '/_mknotif_final.py';
  const pyScript = `import os, math
os.makedirs('/ffmpeg/config/overlay', exist_ok=True)
from PIL import Image, ImageDraw, ImageFilter, ImageFont

W=1040; TITLE_H=44; CONTENT_H=82; TOTAL_H=TITLE_H+CONTENT_H; R=18
SHADOW_BLUR=11; PAD=20
ICON_SZ=22; ICON_X=14; ICON_Y=(TITLE_H-ICON_SZ)//2

# Draw Messages icon at 4x then downsample (smooth antialiasing)
SZ4=ICON_SZ*4
big=Image.new('RGBA',(SZ4,SZ4),(0,0,0,0))
bd=ImageDraw.Draw(big)
bd.rounded_rectangle([0,0,SZ4-1,SZ4-1],radius=SZ4//4,fill=(52,199,89,255))
pad1=SZ4//8
bd.ellipse([pad1,pad1,SZ4-pad1-1,SZ4-pad1-6],fill=(255,255,255,255))
tail=[(pad1+2,SZ4-pad1-8),(pad1+2,SZ4-pad1+6),(pad1+SZ4//6,SZ4-pad1-14)]
bd.polygon(tail,fill=(255,255,255,255))
icon=big.resize((ICON_SZ,ICON_SZ),Image.LANCZOS)

# Shadow
full_w=W+PAD*2; full_h=TOTAL_H+PAD*2+10
shadow=Image.new('RGBA',(full_w,full_h),(0,0,0,0))
ImageDraw.Draw(shadow).rounded_rectangle([PAD,PAD+8,PAD+W-1,PAD+TOTAL_H+8-1],radius=R,fill=(0,0,0,72))
shadow=shadow.filter(ImageFilter.GaussianBlur(SHADOW_BLUR))

# Card
card=Image.new('RGBA',(W,TOTAL_H),(0,0,0,0))
mask=Image.new('L',(W,TOTAL_H),0)
ImageDraw.Draw(mask).rounded_rectangle([0,0,W-1,TOTAL_H-1],radius=R,fill=255)
card.paste(Image.new('RGBA',(W,TITLE_H),(255,255,255,250)),(0,0))
ImageDraw.Draw(card).rectangle([0,TITLE_H,W,TITLE_H+1],fill=(208,208,212,255))
card.paste(Image.new('RGBA',(W,CONTENT_H),(230,230,234,250)),(0,TITLE_H+1))
card.putalpha(mask)

# Light sweep (per-pixel, no putalpha)
sweep=Image.new('RGBA',(W,TITLE_H),(0,0,0,0))
sp=sweep.load()
for y in range(TITLE_H):
  for x in range(W):
    dv=(x*0.75+y*0.25)/(W*0.75+TITLE_H*0.25)
    if 0.06<dv<0.30:
      t=(dv-0.06)/0.24
      sp[x,y]=(255,255,255,int(18*math.sin(math.pi*t)))
tc=card.crop((0,0,W,TITLE_H))
card.paste(Image.alpha_composite(tc,sweep),(0,0))
card.paste(icon,(ICON_X,ICON_Y),icon)

result=shadow.copy()
result.paste(card,(PAD,PAD),card)
result.save('/ffmpeg/config/overlay/ios_notification_bg.png','PNG')
print('NOTIF_OK')
`;
  fs.writeFileSync(pyPath, pyScript);
  const pyRes = run('docker exec qpc_ffmpeg_runner python3 "' + pyPath.replace('/data/ffmpeg','/ffmpeg') + '"', 30000);
  console.log('Notification card:', pyRes.trim());
}

const hasNotif = run('docker exec qpc_ffmpeg_runner test -f "' + notifBase + '" && echo OK').includes('OK');
console.log('Notification PNG: ' + (hasNotif ? 'READY (rounded corners)' : 'using drawbox fallback'));

// ─── STEP 2: Normalize all clips to 1080x1920 ───────────────────────────────
for (let i = 0; i < N; i++) {
  const inFile  = clips[i].replace('/data/ffmpeg', '/ffmpeg');
  const outFile = contIn + '/' + jobId + '_norm' + i + '.mp4';
  run(
    'docker exec qpc_ffmpeg_runner ffmpeg -y -i "' + inFile + '" ' +
    '-vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black" ' +
    '-r 24 -c:v libx264 -crf 20 -preset fast -pix_fmt yuv420p -an "' + outFile + '"',
    120000
  );
}

// ─── STEP 3: XFADE transitions (variety cycle) ──────────────────────────────
const transitions = ['fade', 'wipeleft', 'slidedown', 'circlecrop', 'wiperight', 'slideleft'];
const CLIP_DUR = 5.0;
const FADE_DUR = 0.4;
let withTransitions;

if (N === 1) {
  withTransitions = contIn + '/' + jobId + '_norm0.mp4';
} else {
  const inputs = Array.from({length:N}, (_,i) => '-i "' + contIn + '/' + jobId + '_norm' + i + '.mp4"').join(' ');
  let xf = '';
  let prev = '[0:v]';
  for (let i = 1; i < N; i++) {
    const t   = transitions[(i-1) % transitions.length];
    const off = (i * (CLIP_DUR - FADE_DUR)).toFixed(1);
    const o   = (i === N-1) ? '[vout]' : '[x'+i+']';
    xf += prev + '['+i+':v]xfade=transition='+t+':duration='+FADE_DUR+':offset='+off+o+';';
    prev = o;
  }
  run(
    'docker exec qpc_ffmpeg_runner ffmpeg -y ' + inputs +
    ' -filter_complex "' + xf.slice(0,-1) + '" -map "[vout]" -c:v libx264 -crf 20 -preset fast -pix_fmt yuv420p "' +
    contIn + '/' + jobId + '_xfade.mp4"',
    300000
  );
  withTransitions = contIn + '/' + jobId + '_xfade.mp4';
}

// ─── STEP 4: Check assets ───────────────────────────────────────────────────
// No logo overlay for fitness channel — text-only branding
const hasLogo = false;

let narFile = data.audio_path || null;
if (narFile) {
  const c = narFile.replace('/data/ffmpeg','/ffmpeg');
  narFile  = run('docker exec qpc_ffmpeg_runner test -f "' + c + '" && echo OK').includes('OK') ? c : null;
}

let bgmFile = data.bgm_path ? data.bgm_path.replace('/data/ffmpeg','/ffmpeg') : null;
const hasBgm = !!(bgmFile && run('docker exec qpc_ffmpeg_runner test -f "' + bgmFile + '" && echo OK').includes('OK'));

const assFile = data.ass_path ? data.ass_path.replace('/data/ffmpeg','/ffmpeg') : null;
const hasAss  = !!(assFile && run('docker exec qpc_ffmpeg_runner test -f "' + assFile + '" && echo OK').includes('OK'));

// Notification bell sound
const notifSndPath = '/ffmpeg/config/whatsapp_notify.mp3';
const hasNotifSnd  = run('docker exec qpc_ffmpeg_runner test -f "' + notifSndPath + '" && echo OK').includes('OK');
console.log('Assets | logo:'+hasLogo+' | voice:'+!!narFile+' | bgm:'+hasBgm+' | ass:'+hasAss+' | bell:'+hasNotifSnd);

// ─── STEP 5: Build FFmpeg input list ────────────────────────────────────────
const inp        = ['-i "' + withTransitions + '"'];
const notifI     = hasNotif    ? inp.push('-i "' + notifBase    + '"') - 1 : -1;
const narI       = narFile     ? inp.push('-i "' + narFile      + '"') - 1 : -1;
const bgmI       = hasBgm      ? inp.push('-i "' + bgmFile      + '"') - 1 : -1;
const notifSndI  = hasNotifSnd ? inp.push('-i "' + notifSndPath + '"') - 1 : -1;

// ─── STEP 6: Video filter chain ─────────────────────────────────────────────
let lbl = 0;
let vf  = '';
let cur = '0:v';

// No channel branding overlay — clean video output

// ─── POPUP NOTIFICATION — iOS Messages style, full width, slide-in ──────────
const popupStart = popup.start_sec || 5;
const popupEnd   = popup.end_sec   || 9;

function ffText(s) {
  return (s||'').replace(/[\\':]/g,'').replace(/[^\x20-\x7E]/g,'').slice(0,52);
}
const pApp = ffText(popup.app_name || 'FitChannel');
const pMsg = ffText(popup.message  || 'Get the full program');
const en   = "between(t," + popupStart + "," + popupEnd + ")";

// Slide in from y=-10 → y=20 over 0.35s (image placed at y=20 final)
const animY =
  "if(between(t," + popupStart + "," + (popupStart+0.35).toFixed(2) + ")," +
    "20-30*(1-((t-" + popupStart + ")/0.35))," +
  "20)";

if (hasNotif) {
  // Scale PNG to 1080×176, overlay full-width at x=0 with slide animation
  vf += ';['+notifI+':v]scale=1080:176,format=rgba[notif]';
  vf += ';['+cur+'][notif]overlay=x=0:y=\''+animY+'\''+
        ':format=auto:enable=\''+en+'\'[vb'+lbl+']';
  cur='vb'+lbl; lbl++;

  // Title bar text — Liberation Sans style (ffmpeg default closest match)
  vf += ';['+cur+"]drawtext=text='MESSAGES':fontcolor=0x646468:fontsize=20:x=64:y=52:enable='"+en+"'[vb"+lbl+']';
  cur='vb'+lbl; lbl++;
  vf += ';['+cur+"]drawtext=text='now':fontcolor=0x9B9BA0:fontsize=20:x=1008:y=52:enable='"+en+"'[vb"+lbl+']';
  cur='vb'+lbl; lbl++;

  // App name bold (double-draw 1px offset for bold effect)
  vf += ';['+cur+"]drawtext=text='"+pApp+"':fontfile=/data/ffmpeg/config/fonts/LiberationSans-Bold.ttf:fontcolor=0x0F0F0F:fontsize=27:x=34:y=95:enable='"+en+"'[vb"+lbl+']';
  cur='vb'+lbl; lbl++;
  vf += ';['+cur+"]drawtext=text='"+pApp+"':fontfile=/data/ffmpeg/config/fonts/LiberationSans-Bold.ttf:fontcolor=0x0F0F0F:fontsize=27:x=35:y=95:enable='"+en+"'[vb"+lbl+']';
  cur='vb'+lbl; lbl++;

  // Message text
  vf += ';['+cur+"]drawtext=text='"+pMsg+"':fontcolor=0x4B4B50:fontsize=24:x=34:y=131:enable='"+en+"'[vb"+lbl+']';
  cur='vb'+lbl; lbl++;

} else {
  // Fallback drawbox
  vf += ';['+cur+']drawbox=x=20:y=40:w=1040:h=44:color=0xFFFFFF@0.97:t=fill:enable=\''+en+'\'[vb'+lbl+']'; cur='vb'+lbl; lbl++;
  vf += ';['+cur+']drawbox=x=20:y=84:w=1040:h=82:color=0xE6E6EA@0.97:t=fill:enable=\''+en+'\'[vb'+lbl+']'; cur='vb'+lbl; lbl++;
  vf += ';['+cur+']drawbox=x=34:y=51:w=22:h=22:color=0x34C759@1:t=fill:enable=\''+en+'\'[vb'+lbl+']'; cur='vb'+lbl; lbl++;
  vf += ';['+cur+"]drawtext=text='MESSAGES':fontcolor=0x646468:fontsize=20:x=64:y=52:enable='"+en+"'[vb"+lbl+']'; cur='vb'+lbl; lbl++;
  vf += ';['+cur+"]drawtext=text='now':fontcolor=0x9B9BA0:fontsize=20:x=1008:y=52:enable='"+en+"'[vb"+lbl+']'; cur='vb'+lbl; lbl++;
  vf += ';['+cur+"]drawtext=text='"+pApp+"':fontcolor=0x0F0F0F:fontsize=27:x=34:y=95:enable='"+en+"'[vb"+lbl+']'; cur='vb'+lbl; lbl++;
  vf += ';['+cur+"]drawtext=text='"+pMsg+"':fontcolor=0x4B4B50:fontsize=24:x=34:y=131:enable='"+en+"'[vb"+lbl+']'; cur='vb'+lbl; lbl++;
}

// ─── MUSCLE LABELS — glowing text + dashed lines via Python PIL overlay ────────
const labelStart = 15, labelEnd = 20;
const labelEn = "between(t," + labelStart + "," + labelEnd + ")";

// Fade in over 0.5s at t=15, fade out over 0.5s at t=19.5
const labelAlpha = "if(between(t,15,15.5),(t-15)/0.5,if(between(t,19.5,20),(20-t)/0.5,1))";

if (muscleLabels && muscleLabels.length > 0) {
  // Generate label overlay PNG via Python PIL
  const labelPngHost = n8nIn + '/' + jobId + '_labels.png';
  const labelPngCont = contIn + '/' + jobId + '_labels.png';

  // Write gen script to input dir
  const genScript = n8nIn + '/_gen_labels.py';
  if (!fs.existsSync(genScript)) {
    // Copy the script if not there (first run) — embedded version
    const scriptSrc = '/data/ffmpeg/input/_gen_labels.py';
    if (fs.existsSync(scriptSrc)) {
      fs.copyFileSync(scriptSrc, genScript);
    }
  }

  const labelsJson = JSON.stringify(muscleLabels).replace(/"/g, '\"');
  const pyCmd = 'docker exec qpc_ffmpeg_runner python3 /ffmpeg/input/_gen_labels.py ' +
    '"' + labelsJson + '" ' +
    '"' + labelPngCont + '" 1080 1920';
  const pyRes = run(pyCmd, 60000);
  console.log('Label overlay:', pyRes.trim());

  const hasLabelPng = fs.existsSync(labelPngHost);
  if (hasLabelPng) {
    const labelI = inp.push('-i "' + labelPngCont + '"') - 1;
    // Overlay with fade-in/out animation
    vf += ';[' + labelI + ':v]format=rgba[labels_raw]';
    vf += ';[' + cur + '][labels_raw]overlay=x=0:y=0:format=auto' +
          ':enable=\'' + labelEn + '\'[vb' + lbl + ']';
    cur = 'vb' + lbl; lbl++;
    console.log('Muscle label PNG overlay added | labels: ' + muscleLabels.length);
  } else {
    console.warn('Label PNG not generated — falling back to drawtext');
    for (const ml of muscleLabels) {
      if (!ml.name) continue;
      const name = ml.name.replace(/['"\:]/g,'').slice(0,28).toUpperCase();
      const lx = Math.max(20, Math.min(840, Math.round((ml.x_pct||0.5)*1080)-130));
      const ly = Math.max(20, Math.min(1860, Math.round((ml.y_pct||0.5)*1920)-20));
      vf += ';['+cur+"]drawtext=text='"+name+"':fontcolor=white:fontsize=52:x="+lx+":y="+ly+":bordercolor=black:borderw=4:enable='"+labelEn+"'[vb"+lbl+']';
      cur='vb'+lbl; lbl++;
    }
  }
}

// ─── ASS Subtitles ───────────────────────────────────────────────────────────
if (hasAss) {
  vf += ";["+cur+"]subtitles=filename='"+assFile+"':fontsdir='/ffmpeg/config/fonts'[outv]";
} else {
  vf += ";["+cur+"]copy[outv]";
}

// ─── Audio mix (narration + BGM + notification bell) ─────────────────────────
let afilters = '';
let amap     = '-an';
const bellDelayMs = Math.round((popup.start_sec || 5) * 1000);

// Bell filter: delay to popup timestamp, volume boost
const bellF = hasNotifSnd
  ? '['+notifSndI+':a]adelay='+bellDelayMs+'|'+bellDelayMs+',volume=2.2,aformat=sample_fmts=fltp[bell];'
  : '';

// Narration trimmed to exact video duration + 0.5s fade-out
const narTrim = 'atrim=0:' + audioCap.toFixed(3) + ',afade=t=out:st=' + Math.max(0,(audioCap-0.6)).toFixed(3) + ':d=0.6,volume=1.0';
const narF    = narFile ? '['+narI+':a]'+narTrim+'[nar];' : '';

if (narFile && hasBgm && hasNotifSnd) {
  afilters = ';'+narF+bellF+'[bgm_raw]'+('['+bgmI+':a]')+';[bgm_raw]atrim=0:'+dur+',volume=0.22[bgm];[nar][bgm][bell]amix=inputs=3:duration=first:dropout_transition=2[aout]';
  amap = '-map "[aout]"';
} else if (narFile && hasBgm) {
  afilters = ';'+narF+'['+bgmI+':a]atrim=0:'+dur+',volume=0.22[bgm];[nar][bgm]amix=inputs=2:duration=first:dropout_transition=2[aout]';
  amap = '-map "[aout]"';
} else if (narFile && hasNotifSnd) {
  afilters = ';'+narF+bellF+'[nar][bell]amix=inputs=2:duration=first:dropout_transition=2[aout]';
  amap = '-map "[aout]"';
} else if (narFile) {
  afilters = ';'+narF+'[nar]aformat=sample_fmts=fltp[aout]';
  amap = '-map "[aout]"';
} else if (hasBgm) {
  afilters = ';['+bgmI+':a]atrim=0:'+dur+',volume=0.85[aout]';
  amap = '-map "[aout]"';
}

const fullFilter = (vf + afilters).replace(/^;/, "");

// ── Calculate exact video duration (clips with xfade overlaps) ────────────────
const CLIP_DUR_S = 5.0;
const FADE_DUR_S = 0.4;
const videoDur   = N * CLIP_DUR_S - Math.max(0, N-1) * FADE_DUR_S;  // e.g. 6×5 - 5×0.4 = 28s
// Cap audio at video duration — prevent black tail at end
const audioCap   = data.audio_duration ? Math.min(data.audio_duration, videoDur) : videoDur;
const dur        = Math.ceil(videoDur) + 1;  // +1s buffer for smooth fade-out
console.log('Video dur: ' + videoDur.toFixed(1) + 's | Audio dur: ' + (data.audio_duration||0).toFixed(1) + 's | Capped to: ' + audioCap.toFixed(1) + 's');
const hasAudio   = amap !== '-an';

console.log('Filter nodes: '+lbl+' | audio:'+hasAudio+' | subtitles:'+hasAss+' | popup_png:'+hasNotif);

// ─── Final render ─────────────────────────────────────────────────────────────
const cmd =
  'docker exec qpc_ffmpeg_runner ffmpeg -y ' + inp.join(' ') +
  ' -filter_complex "' + fullFilter + '" -map "[outv]" ' + amap +
  ' -c:v libx264 -crf 18 -preset fast -pix_fmt yuv420p -movflags +faststart' +
  (hasAudio ? ' -c:a aac -b:a 192k' : '') +
  ' -t ' + dur + ' "' + contOut + '/' + jobId + '_final.mp4" && echo FINAL_OK';

const result = run(cmd, 900000);
if (!result.includes('FINAL_OK')) throw new Error('Final render failed:\n' + result.slice(-800));

const finalPath = n8nOut + '/' + jobId + '_final.mp4';
if (!fs.existsSync(finalPath)) throw new Error('Output not on disk: ' + finalPath);

const elapsed = Math.round((Date.now() - data.start_time) / 1000);
console.log('Assembly complete | ' + jobId + ' | ' + elapsed + 's | ' + finalPath);

return [{ json: { ...data, final_video_path: finalPath, output_filename: jobId + '_final.mp4', assembly_time_sec: elapsed } }];

const fs           = require('fs');
