if (!fs.existsSync(filePath)) throw new Error('Final video missing: ' + filePath);

const folderId = $env.GOOGLE_DRIVE_FOLDER_ID || '';
const token    = $env.GOOGLE_DRIVE_ACCESS_TOKEN || '';

