  console.log('Video ready at: ' + filePath);
  return [{ json: { ...data, drive_file_id: null, drive_video_url: null, drive_skipped: true } }];
}

const metadata    = JSON.stringify({ name: data.output_filename, parents: [folderId] });
const escapedMeta = metadata.replace(/"/g, '\\"');

